esqlQuery.esql:
TS metrics-mongodbreceiver.otel-default
// Scope to MongoDB OTel metrics
| WHERE data_stream.dataset == "mongodbreceiver.otel"
| WHERE metrics.mongodb.session.count IS NOT NULL
// Current active session count (gauge)
| STATS sessions = MAX(LAST_OVER_TIME(metrics.mongodb.session.count)) BY resource.attributes.server.address
// Alert when session count exceeds threshold (possible pool misconfiguration; adjust 500 for your setup)
| WHERE sessions > 500
| SORT sessions DESC
| LIMIT 20
